export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    // CORS headers for public access
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      // Request context passed to internal services
      const requestContext = {
        requestId: crypto.randomUUID(),
        timestamp: Date.now(),
        clientIp: request.headers.get('CF-Connecting-IP'),
        userAgent: request.headers.get('User-Agent'),
        country: request.headers.get('CF-IPCountry'),
      };

      // Attach context as headers for downstream services
      const contextHeaders = new Headers(request.headers);
      contextHeaders.set('X-Request-Id', requestContext.requestId);
      contextHeaders.set('X-Request-Timestamp', requestContext.timestamp.toString());
      contextHeaders.set('X-Client-IP', requestContext.clientIp || 'unknown');
      contextHeaders.set('X-Client-Country', requestContext.country || 'unknown');

      let response;

      // Route to appropriate internal service via Service Bindings
      if (path.startsWith('/api/auth')) {
        response = await routeToService(env.AUTH_SERVICE, request, contextHeaders, '/api/auth');
      } else if (path.startsWith('/api/users')) {
        response = await routeToService(env.USER_SERVICE, request, contextHeaders, '/api/users');
      } else if (path.startsWith('/api/data')) {
        response = await routeToService(env.DATA_SERVICE, request, contextHeaders, '/api/data');
      } else if (path.startsWith('/api/notifications')) {
        response = await routeToService(env.NOTIFICATION_SERVICE, request, contextHeaders, '/api/notifications');
      } else if (path === '/api/health') {
        response = await healthCheck(env, requestContext);
      } else if (path === '/api/aggregate') {
        // Demonstrate fan-out: call multiple services and aggregate
        response = await aggregateResponses(env, request, contextHeaders);
      } else {
        response = new Response(JSON.stringify({
          error: 'Not Found',
          message: `No route matched for ${path}`,
          requestId: requestContext.requestId,
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' },
        });
      }

      // Clone response and add CORS + tracking headers
      const newHeaders = new Headers(response.headers);
      Object.entries(corsHeaders).forEach(([key, value]) => {
        newHeaders.set(key, value);
      });
      newHeaders.set('X-Request-Id', requestContext.requestId);
      newHeaders.set('X-Response-Time', `${Date.now() - requestContext.timestamp}ms`);
      newHeaders.set('X-Served-By', 'edge-gateway');

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: newHeaders,
      });

    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Gateway Error',
        message: error.message,
      }), {
        status: 502,
        headers: { 'Content-Type': 'application/json', ...corsHeaders },
      });
    }
  },
};

async function routeToService(serviceBinding, originalRequest, contextHeaders, basePath) {
  if (!serviceBinding) {
    return new Response(JSON.stringify({
      error: 'Service Unavailable',
      message: `Service binding not configured for ${basePath}`,
    }), {
      status: 503,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  const url = new URL(originalRequest.url);
  // Strip the base path prefix so internal services get clean paths
  const internalPath = url.pathname.substring(basePath.length) || '/';
  const internalUrl = new URL(internalPath + url.search, 'http://internal-service');

  const internalRequest = new Request(internalUrl.toString(), {
    method: originalRequest.method,
    headers: contextHeaders,
    body: originalRequest.method !== 'GET' && originalRequest.method !== 'HEAD'
      ? originalRequest.body
      : undefined,
  });

  return serviceBinding.fetch(internalRequest);
}

async function healthCheck(env, requestContext) {
  const services = {
    AUTH_SERVICE: env.AUTH_SERVICE,
    USER_SERVICE: env.USER_SERVICE,
    DATA_SERVICE: env.DATA_SERVICE,
    NOTIFICATION_SERVICE: env.NOTIFICATION_SERVICE,
  };

  const results = {};

  await Promise.all(
    Object.entries(services).map(async ([name, binding]) => {
      if (!binding) {
        results[name] = { status: 'not_configured' };
        return;
      }
      try {
        const start = Date.now();
        const resp = await binding.fetch(new Request('http://internal-service/health'));
        const latency = Date.now() - start;
        const body = await resp.json();
        results[name] = { status: 'healthy', latency: `${latency}ms`, details: body };
      } catch (error) {
        results[name] = { status: 'unhealthy', error: error.message };
      }
    })
  );

  return new Response(JSON.stringify({
    gateway: 'healthy',
    requestId: requestContext.requestId,
    services: results,
    timestamp: new Date().toISOString(),
  }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}

async function aggregateResponses(env, request, contextHeaders) {
  const [userResponse, dataResponse] = await Promise.allSettled([
    env.USER_SERVICE
      ? env.USER_SERVICE.fetch(new Request('http://internal-service/summary', { headers: contextHeaders }))
      : Promise.reject(new Error('User service not bound')),
    env.DATA_SERVICE
      ? env.DATA_SERVICE.fetch(new Request('http://internal-service/summary', { headers: contextHeaders }))
      : Promise.reject(new Error('Data service not bound')),
  ]);

  const aggregate = {
    users: userResponse.status === 'fulfilled'
      ? await userResponse.value.json()
      : { error: userResponse.reason?.message },
    data: dataResponse.status === 'fulfilled'
      ? await dataResponse.value.json()
      : { error: dataResponse.reason?.message },
  };

  return new Response(JSON.stringify(aggregate), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}


