export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-Id') || 'unknown';

    // Internal service middleware: log incoming requests
    console.log(`[AUTH] ${method} ${path} | requestId=${requestId}`);

    try {
      if (path === '/health') {
        return jsonResponse({ service: 'auth', status: 'healthy', timestamp: Date.now() });
      }

      if (path === '/login' && method === 'POST') {
        return await handleLogin(request, env);
      }

      if (path === '/verify' && method === 'POST') {
        return await handleVerify(request, env);
      }

      if (path === '/refresh' && method === 'POST') {
        return await handleRefresh(request, env);
      }

      if (path === '/logout' && method === 'POST') {
        return await handleLogout(request, env);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (error) {
      console.error(`[AUTH] Error: ${error.message}`);
      return jsonResponse({ error: 'Internal Service Error', message: error.message, requestId }, 500);
    }
  },
};

async function handleLogin(request, env) {
  const body = await request.json();
  const { email, password } = body;

  if (!email || !password) {
    return jsonResponse({ error: 'Email and password required' }, 400);
  }

  // Simulate authentication (in production, check against KV/D1/external auth)
  // Use KV to store/check sessions
  const userId = await authenticateUser(env, email, password);

  if (!userId) {
    return jsonResponse({ error: 'Invalid credentials' }, 401);
  }

  const token = await generateToken(userId, email);
  const sessionId = crypto.randomUUID();

  // Store session in KV if available
  if (env.SESSIONS_KV) {
    await env.SESSIONS_KV.put(`session:${sessionId}`, JSON.stringify({
      userId,
      email,
      token,
      createdAt: Date.now(),
    }), { expirationTtl: 86400 }); // 24h
  }

  // Notify via notification service if bound
  if (env.NOTIFICATION_SERVICE) {
    ctx?.waitUntil(
      env.NOTIFICATION_SERVICE.fetch(new Request('http://internal-service/emit', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'user.login',
          userId,
          email,
          timestamp: Date.now(),
        }),
      })).catch(err => console.error('Failed to notify:', err))
    );
  }

  return jsonResponse({
    success: true,
    token,
    sessionId,
    userId,
    expiresIn: 86400,
  });
}

async function handleVerify(request, env) {
  const body = await request.json();
  const { token } = body;

  if (!token) {
    return jsonResponse({ error: 'Token required' }, 400);
  }

  const payload = await verifyToken(token);

  if (!payload) {
    return jsonResponse({ error: 'Invalid or expired token', valid: false }, 401);
  }

  return jsonResponse({ valid: true, userId: payload.userId, email: payload.email });
}

async function handleRefresh(request, env) {
  const body = await request.json();
  const { sessionId } = body;

  if (!sessionId || !env.SESSIONS_KV) {
    return jsonResponse({ error: 'Session refresh not available' }, 400);
  }

  const sessionData = await env.SESSIONS_KV.get(`session:${sessionId}`, { type: 'json' });

  if (!sessionData) {
    return jsonResponse({ error: 'Session expired or not found' }, 401);
  }

  const newToken = await generateToken(sessionData.userId, sessionData.email);
  const newSessionId = crypto.randomUUID();

  await env.SESSIONS_KV.delete(`session:${sessionId}`);
  await env.SESSIONS_KV.put(`session:${newSessionId}`, JSON.stringify({
    ...sessionData,
    token: newToken,
    createdAt: Date.now(),
  }), { expirationTtl: 86400 });

  return jsonResponse({ token: newToken, sessionId: newSessionId, expiresIn: 86400 });
}

async function handleLogout(request, env) {
  const body = await request.json();
  const { sessionId } = body;

  if (sessionId && env.SESSIONS_KV) {
    await env.SESSIONS_KV.delete(`session:${sessionId}`);
  }

  return jsonResponse({ success: true, message: 'Logged out' });
}

async function authenticateUser(env, email, password) {
  // In production, check against D1 database or external API
  // Simplified for demonstration
  if (env.USERS_KV) {
    const userData = await env.USERS_KV.get(`user:${email}`, { type: 'json' });
    if (userData) {
      const encoder = new TextEncoder();
      const data = encoder.encode(password + userData.salt);
      const hashBuffer = await crypto.subtle.digest('SHA-256', data);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
      if (hashHex === userData.passwordHash) {
        return userData.userId;
      }
    }
  }

  // Fallback demo: accept test credentials
  if (email === 'test@example.com' && password === 'password') {
    return 'user_demo_001';
  }

  return null;
}

async function generateToken(userId, email) {
  const header = btoa(JSON.stringify({ alg: 'HS256', typ: 'JWT' }));
  const payload = btoa(JSON.stringify({
    userId,
    email,
    iat: Math.floor(Date.now() / 1000),
    exp: Math.floor(Date.now() / 1000) + 86400,
  }));

  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode('edge-microservices-secret-key'),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );

  const signature = await crypto.subtle.sign(
    'HMAC',
    key,
    encoder.encode(`${header}.${payload}`)
  );

  const sig = btoa(String.fromCharCode(...new Uint8Array(signature)));
  return `${header}.${payload}.${sig}`;
}

async function verifyToken(token) {
  try {
    const [header, payload, signature] = token.split('.');
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode('edge-microservices-secret-key'),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['verify']
    );

    const sigBytes = Uint8Array.from(atob(signature), c => c.charCodeAt(0));
    const valid = await crypto.subtle.verify(
      'HMAC',
      key,
      sigBytes,
      encoder.encode(`${header}.${payload}`)
    );

    if (!valid) return null;

    const decoded = JSON.parse(atob(payload));
    if (decoded.exp < Math.floor(Date.now() / 1000)) return null;

    return decoded;
  } catch {
    return null;
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', 'X-Service': 'auth-worker' },
  });
}


