// ==========================================
// worker-user/src/index.js
// Internal User Service Worker
// ==========================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-Id') || 'unknown';

    console.log(`[USER] ${method} ${path} | requestId=${requestId}`);

    // Authentication middleware for protected routes
    if (path !== '/health' && path !== '/summary') {
      const authResult = await authenticateRequest(request, env);
      if (!authResult.authenticated) {
        return jsonResponse({ error: 'Unauthorized', message: authResult.error }, 401);
      }
      // Attach user info to request context
      request = new Request(request.url, {
        method: request.method,
        headers: (() => {
          const h = new Headers(request.headers);
          h.set('X-User-Id', authResult.userId);
          h.set('X-User-Email', authResult.email);
          return h;
        })(),
        body: request.body,
      });
    }

    try {
      if (path === '/health') {
        return jsonResponse({ service: 'user', status: 'healthy', timestamp: Date.now() });
      }

      if (path === '/summary') {
        return await handleSummary(env);
      }

      if (path === '/profile' && method === 'GET') {
        return await handleGetProfile(request, env);
      }

      if (path === '/profile' && method === 'PUT') {
        return await handleUpdateProfile(request, env, ctx);
      }

      if (path === '/list' && method === 'GET') {
        return await handleListUsers(request, env);
      }

      // CRUD with path params: /123
      const userIdMatch = path.match(/^\/([a-zA-Z0-9_-]+)$/);
      if (userIdMatch) {
        const userId = userIdMatch[1];
        if (method === 'GET') return await handleGetUser(userId, env);
        if (method === 'PUT') return await handleUpdateUser(userId, request, env, ctx);
        if (method === 'DELETE') return await handleDeleteUser(userId, request, env, ctx);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (error) {
      console.error(`[USER] Error: ${error.message}`);
      return jsonResponse({ error: 'Internal Service Error', message: error.message, requestId }, 500);
    }
  },
};

async function authenticateRequest(request, env) {
  const authHeader = request.headers.get('Authorization');

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return { authenticated: false, error: 'Missing or invalid Authorization header' };
  }

  const token = authHeader.substring(7);

  // Call auth service via service binding to verify token
  if (env.AUTH_SERVICE) {
    try {
      const verifyResponse = await env.AUTH_SERVICE.fetch(
        new Request('http://internal-service/verify', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ token }),
        })
      );

      const result = await verifyResponse.json();

      if (result.valid) {
        return { authenticated: true, userId: result.userId, email: result.email };
      }

      return { authenticated: false, error: 'Invalid token' };
    } catch (error) {
      console.error('Auth service error:', error);
      return { authenticated: false, error: 'Auth service unavailable' };
    }
  }

  return { authenticated: false, error: 'Auth service not configured' };
}

async function handleGetProfile(request, env) {
  const userId = request.headers.get('X-User-Id');

  if (env.USERS_KV) {
    const profile = await env.USERS_KV.get(`profile:${userId}`, { type: 'json' });
    if (profile) {
      return jsonResponse({ userId, profile });
    }
  }

  return jsonResponse({
    userId,
    profile: {
      email: request.headers.get('X-User-Email'),
      name: 'Demo User',
      createdAt: '2024-01-01T00:00:00Z',
    },
  });
}

async function handleUpdateProfile(request, env, ctx) {
  const userId = request.headers.get('X-User-Id');
  const updates = await request.json();

  const allowedFields = ['name', 'bio', 'avatar', 'preferences'];
  const sanitizedUpdates = {};

  for (const field of allowedFields) {
    if (updates[field] !== undefined) {
      sanitizedUpdates[field] = updates[field];
    }
  }

  if (env.USERS_KV) {
    const existing = await env.USERS_KV.get(`profile:${userId}`, { type: 'json' }) || {};
    const updated = { ...existing, ...sanitizedUpdates, updatedAt: new Date().toISOString() };
    await env.USERS_KV.put(`profile:${userId}`, JSON.stringify(updated));
  }

  // Emit event to notification service
  if (env.NOTIFICATION_SERVICE) {
    ctx?.waitUntil(
      env.NOTIFICATION_SERVICE.fetch(new Request('http://internal-service/emit', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'user.profile.updated',
          userId,
          fields: Object.keys(sanitizedUpdates),
          timestamp: Date.now(),
        }),
      })).catch(err => console.error('Notification error:', err))
    );
  }

  return jsonResponse({ success: true, userId, updated: sanitizedUpdates });
}

async function handleGetUser(userId, env) {
  if (env.USERS_KV) {
    const profile = await env.USERS_KV.get(`profile:${userId}`, { type: 'json' });
    if (profile) {
      // Return public profile only
      const { name, bio, avatar, createdAt } = profile;
      return jsonResponse({ userId, profile: { name, bio, avatar, createdAt } });
    }
  }

  return jsonResponse({ error: 'User not found' }, 404);
}

async function handleUpdateUser(userId, request, env, ctx) {
  const updates = await request.json();

  if (env.USERS_KV) {
    const existing = await env.USERS_KV.get(`profile:${userId}`, { type: 'json' });
    if (!existing) {
      return jsonResponse({ error: 'User not found' }, 404);
    }
    const updated = { ...existing, ...updates, updatedAt: new Date().toISOString() };
    await env.USERS_KV.put(`profile:${userId}`, JSON.stringify(updated));
    return jsonResponse({ success: true, userId });
  }

  return jsonResponse({ error: 'Storage not available' }, 503);
}

async function handleDeleteUser(userId, request, env, ctx) {
  if (env.USERS_KV) {
    await env.USERS_KV.delete(`profile:${userId}`);

    if (env.NOTIFICATION_SERVICE) {
      ctx?.waitUntil(
        env.NOTIFICATION_SERVICE.fetch(new Request('http://internal-service/emit', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'user.deleted',
            userId,
            timestamp: Date.now(),
          }),
        })).catch(err => console.error('Notification error:', err))
      );
    }

    return jsonResponse({ success: true, deleted: userId });
  }

  return jsonResponse({ error: 'Storage not available' }, 503);
}

async function handleListUsers(request, env) {
  const url = new URL(request.url);
  const prefix = url.searchParams.get('prefix') || 'profile:';
  const limit = parseInt(url.searchParams.get('limit') || '20', 10);

  if (env.USERS_KV) {
    const list = await env.USERS_KV.list({ prefix, limit });
    return jsonResponse({
      users: list.keys.map(k => ({
        userId: k.name.replace('profile:', ''),
        metadata: k.metadata,
      })),
      cursor: list.cursor,
      complete: list.list_complete,
    });
  }

  return jsonResponse({ users: [], complete: true });
}

async function handleSummary(env) {
  let totalUsers = 0;

  if (env.USERS_KV) {
    const list = await env.USERS_KV.list({ prefix: 'profile:' });
    totalUsers = list.keys.length;
  }

  return jsonResponse({
    service: 'user',
    totalUsers,
    timestamp: Date.now(),
  });
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', 'X-Service': 'user-worker' },
  });
}


