export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-Id') || 'unknown';

    console.log(`[DATA] ${method} ${path} | requestId=${requestId}`);

    try {
      if (path === '/health') {
        return jsonResponse({ service: 'data', status: 'healthy', timestamp: Date.now() });
      }

      if (path === '/summary') {
        return await handleSummary(env);
      }

      if (path === '/process' && method === 'POST') {
        return await handleProcess(request, env, ctx);
      }

      if (path === '/query' && method === 'POST') {
        return await handleQuery(request, env);
      }

      if (path === '/batch' && method === 'POST') {
        return await handleBatchProcess(request, env, ctx);
      }

      // Key-value data operations
      if (path.startsWith('/store')) {
        return await handleDataStore(path, method, request, env);
      }

      // D1 database operations
      if (path.startsWith('/db')) {
        return await handleDatabaseOps(path, method, request, env);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (error) {
      console.error(`[DATA] Error: ${error.message}`);
      return jsonResponse({ error: 'Internal Service Error', message: error.message, requestId }, 500);
    }
  },
};

async function handleProcess(request, env, ctx) {
  const body = await request.json();
  const { type, payload } = body;

  const processors = {
    transform: processTransform,
    aggregate: processAggregate,
    filter: processFilter,
    enrich: processEnrich,
  };

  const processor = processors[type];
  if (!processor) {
    return jsonResponse({ error: `Unknown process type: ${type}` }, 400);
  }

  const startTime = Date.now();
  const result = await processor(payload, env);
  const processingTime = Date.now() - startTime;

  // Store processing metrics
  if (env.METRICS_KV) {
    ctx?.waitUntil(
      env.METRICS_KV.put(
        `metric:process:${Date.now()}`,
        JSON.stringify({ type, processingTime, recordCount: result.recordCount || 0 }),
        { expirationTtl: 86400 }
      )
    );
  }

  return jsonResponse({
    success: true,
    type,
    result,
    processingTime: `${processingTime}ms`,
  });
}

async function processTransform(payload, env) {
  const { data, transformations } = payload;

  if (!Array.isArray(data)) {
    return { error: 'Data must be an array' };
  }

  let transformed = [...data];

  for (const transform of (transformations || [])) {
    switch (transform.operation) {
      case 'map':
        if (transform.field && transform.fn === 'uppercase') {
          transformed = transformed.map(item => ({
            ...item,
            [transform.field]: typeof item[transform.field] === 'string'
              ? item[transform.field].toUpperCase()
              : item[transform.field],
          }));
        }
        break;
      case 'rename':
        if (transform.from && transform.to) {
          transformed = transformed.map(item => {
            const newItem = { ...item };
            newItem[transform.to] = newItem[transform.from];
            delete newItem[transform.from];
            return newItem;
          });
        }
        break;
      case 'addField':
        if (transform.field && transform.value !== undefined) {
          transformed = transformed.map(item => ({
            ...item,
            [transform.field]: transform.value,
          }));
        }
        break;
    }
  }

  return { data: transformed, recordCount: transformed.length };
}

async function processAggregate(payload, env) {
  const { data, groupBy, metrics } = payload;

  if (!Array.isArray(data)) {
    return { error: 'Data must be an array' };
  }

  const groups = {};

  for (const item of data) {
    const key = groupBy ? item[groupBy] : 'all';
    if (!groups[key]) {
      groups[key] = [];
    }
    groups[key].push(item);
  }

  const aggregated = {};

  for (const [key, items] of Object.entries(groups)) {
    aggregated[key] = { count: items.length };

    for (const metric of (metrics || [])) {
      const values = items
        .map(item => item[metric.field])
        .filter(v => typeof v === 'number');

      if (metric.type === 'sum') {
        aggregated[key][`${metric.field}_sum`] = values.reduce((a, b) => a + b, 0);
      } else if (metric.type === 'avg') {
        aggregated[key][`${metric.field}_avg`] = values.length > 0
          ? values.reduce((a, b) => a + b, 0) / values.length
          : 0;
      } else if (metric.type === 'min') {
        aggregated[key][`${metric.field}_min`] = values.length > 0 ? Math.min(...values) : null;
      } else if (metric.type === 'max') {
        aggregated[key][`${metric.field}_max`] = values.length > 0 ? Math.max(...values) : null;
      }
    }
  }

  return { aggregated, groupCount: Object.keys(aggregated).length, recordCount: data.length };
}

async function processFilter(payload, env) {
  const { data, conditions } = payload;

  if (!Array.isArray(data)) {
    return { error: 'Data must be an array' };
  }

  let filtered = [...data];

  for (const condition of (conditions || [])) {
    filtered = filtered.filter(item => {
      const value = item[condition.field];
      switch (condition.operator) {
        case 'eq': return value === condition.value;
        case 'neq': return value !== condition.value;
        case 'gt': return value > condition.value;
        case 'gte': return value >= condition.value;
        case 'lt': return value < condition.value;
        case 'lte': return value <= condition.value;
        case 'contains':
          return typeof value === 'string' && value.includes(condition.value);
        case 'in':
          return Array.isArray(condition.value) && condition.value.includes(value);
        default: return true;
      }
    });
  }

  return { data: filtered, recordCount: filtered.length, originalCount: data.length };
}

async function processEnrich(payload, env) {
  const { data, enrichments } = payload;

  if (!Array.isArray(data)) {
    return { error: 'Data must be an array' };
  }

  const enriched = data.map(item => {
    const newItem = { ...item, _enrichedAt: new Date().toISOString() };

    for (const enrichment of (enrichments || [])) {
      if (enrichment.type === 'timestamp') {
        newItem[enrichment.field || '_timestamp'] = Date.now();
      } else if (enrichment.type === 'hash' && enrichment.sourceField) {
        // Simple hash for demo
        newItem[enrichment.field || `${enrichment.sourceField}_hash`] =
          btoa(String(item[enrichment.sourceField]));
      } else if (enrichment.type === 'lookup' && enrichment.map) {
        const key = item[enrichment.sourceField];
        newItem[enrichment.field || `${enrichment.sourceField}_resolved`] =
          enrichment.map[key] || enrichment.default || null;
      }
    }

    return newItem;
  });

  return { data: enriched, recordCount: enriched.length };
}

async function handleQuery(request, env) {
  const body = await request.json();
  const { collection, filter, sort, limit, offset } = body;

  if (!collection || !env.DATA_KV) {
    return jsonResponse({ error: 'Collection or storage not available' }, 400);
  }

  const listResult = await env.DATA_KV.list({ prefix: `collection:${collection}:` });
  let records = [];

  for (const key of listResult.keys) {
    const value = await env.DATA_KV.get(key.name, { type: 'json' });
    if (value) records.push(value);
  }

  // Apply filters
  if (filter) {
    records = records.filter(record => {
      return Object.entries(filter).every(([field, value]) => record[field] === value);
    });
  }

  // Apply sort
  if (sort) {
    const [field, direction] = Object.entries(sort)[0] || [];
    if (field) {
      records.sort((a, b) => {
        if (direction === 'desc') return a[field] > b[field] ? -1 : 1;
        return a[field] > b[field] ? 1 : -1;
      });
    }
  }

  const total = records.length;
  const start = offset || 0;
  const end = start + (limit || 50);
  records = records.slice(start, end);

  return jsonResponse({ records, total, offset: start, limit: limit || 50 });
}

async function handleBatchProcess(request, env, ctx) {
  const body = await request.json();
  const { operations } = body;

  if (!Array.isArray(operations)) {
    return jsonResponse({ error: 'Operations must be an array' }, 400);
  }

  const results = [];

  for (const op of operations) {
    try {
      let result;
      switch (op.type) {
        case 'transform':
          result = await processTransform(op.payload, env);
          break;
        case 'aggregate':
          result = await processAggregate(op.payload, env);
          break;
        case 'filter':
          result = await processFilter(op.payload, env);
          break;
        case 'enrich':
          result = await processEnrich(op.payload, env);
          break;
        default:
          result = { error: `Unknown operation: ${op.type}` };
      }
      results.push({ id: op.id, status: 'success', result });
    } catch (error) {
      results.push({ id: op.id, status: 'error', error: error.message });
    }
  }

  return jsonResponse({
    batchId: crypto.randomUUID(),
    total: operations.length,
    succeeded: results.filter(r => r.status === 'success').length,
    failed: results.filter(r => r.status === 'error').length,
    results,
  });
}

async function handleDataStore(path, method, request, env) {
  const subPath = path.substring('/store'.length);

  if (!env.DATA_KV) {
    return jsonResponse({ error: 'Data storage not configured' }, 503);
  }

  if (subPath === '' || subPath === '/') {
    if (method === 'GET') {
      const prefix = new URL(request.url).searchParams.get('prefix') || '';
      const list = await env.DATA_KV.list({ prefix });
      return jsonResponse({ keys: list.keys, complete: list.list_complete });
    }
  }

  const key = subPath.substring(1); // Remove leading /

  if (method === 'GET') {
    const value = await env.DATA_KV.get(key, { type: 'json' });
    if (!value) return jsonResponse({ error: 'Key not found' }, 404);
    return jsonResponse({ key, value });
  }

  if (method === 'PUT' || method === 'POST') {
    const body = await request.json();
    const ttl = body._ttl ? parseInt(body._ttl, 10) : undefined;
    delete body._ttl;
    await env.DATA_KV.put(key, JSON.stringify(body), ttl ? { expirationTtl: ttl } : {});
    return jsonResponse({ success: true, key });
  }

  if (method === 'DELETE') {
    await env.DATA_KV.delete(key);
    return jsonResponse({ success: true, deleted: key });
  }

  return jsonResponse({ error: 'Method not allowed' }, 405);
}

async function handleDatabaseOps(path, method, request, env) {
  if (!env.DB) {
    return jsonResponse({ error: 'Database not configured' }, 503);
  }

  const subPath = path.substring('/db'.length);

  if (subPath === '/init' && method === 'POST') {
    // Initialize tables
    await env.DB.exec(`
      CREATE TABLE IF NOT EXISTS records (
        id TEXT PRIMARY KEY,
        collection TEXT NOT NULL,
        data TEXT NOT NULL,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
      );
      CREATE INDEX IF NOT EXISTS idx_records_collection ON records(collection);
    `);
    return jsonResponse({ success: true, message: 'Database initialized' });
  }

  if (subPath === '/query' && method === 'POST') {
    const { sql, params } = await request.json();
    // Only allow SELECT statements for safety
    if (!sql.trim().toUpperCase().startsWith('SELECT')) {
      return jsonResponse({ error: 'Only SELECT queries allowed via this endpoint' }, 400);
    }
    const result = await env.DB.prepare(sql).bind(...(params || [])).all();
    return jsonResponse({ results: result.results, meta: result.meta });
  }

  if (subPath === '/insert' && method === 'POST') {
    const { collection, id, data } = await request.json();
    const recordId = id || crypto.randomUUID();
    await env.DB.prepare(
      'INSERT OR REPLACE INTO records (id, collection, data, updated_at) VALUES (?, ?, ?, CURRENT_TIMESTAMP)'
    ).bind(recordId, collection, JSON.stringify(data)).run();
    return jsonResponse({ success: true, id: recordId, collection });
  }

  return jsonResponse({ error: 'Not Found', path: subPath }, 404);
}

async function handleSummary(env) {
  const stats = { service: 'data', timestamp: Date.now() };

  if (env.DATA_KV) {
    const list = await env.DATA_KV.list({});
    stats.kvKeys = list.keys.length;
  }

  if (env.DB) {
    try {
      const result = await env.DB.prepare('SELECT COUNT(*) as count FROM records').first();
      stats.dbRecords = result?.count || 0;
    } catch {
      stats.dbRecords = 'table not initialized';
    }
  }

  return jsonResponse(stats);
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', 'X-Service': 'data-worker' },
  });
}


// ==========================================
// worker-data/wrangler.toml
// ==========================================
/*
name = "data-worker"
main = "src/index.js"
compatibility_date = "2024-01-01"

# No public routes - internal only

[[kv_namespaces]]
binding = "DATA_KV"
id = "your-data-kv-id"

[[kv_namespaces]]
binding = "METRICS_KV"
id = "your-metrics-kv-id"

[[d1_databases]]
binding = "DB"
database_name = "data-service-db"
database_id = "your-d1-database-id"
*/


// ==========================================
// worker-notification/src/index.js
// Internal Notification & Event Service Worker
// ==========================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-Id') || 'unknown';

    console.log(`[NOTIFICATION] ${method} ${path} | requestId=${requestId}`);

    try {
      if (path === '/health') {
        return jsonResponse({ service: 'notification', status: 'healthy', timestamp: Date.now() });
      }

      if (path === '/emit' && method === 'POST') {
        return await handleEmitEvent(request, env, ctx);
      }

      if (path === '/events' && method === 'GET') {
        return await handleListEvents(request, env);
      }

      if (path === '/subscribe' && method === 'POST') {
        return await handleSubscribe(request, env);
      }

      if (path === '/unsubscribe' && method === 'POST') {
        return await handleUnsubscribe(request, env);
      }

      if (path === '/webhooks/dispatch' && method === 'POST') {
        return await handleWebhookDispatch(request, env, ctx);
      }

      if (path === '/stats' && method === 'GET') {
        return await handleStats(env);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (error) {
      console.error(`[NOTIFICATION] Error: ${error.message}`);
      return jsonResponse({ error: 'Internal Service Error', message: error.message, requestId }, 500);
    }
  },

  // Queue consumer for async event processing
  async queue(batch, env) {
    for (const message of batch.messages) {
      try {
        const event = message.body;
        console.log(`[NOTIFICATION] Queue processing event: ${event.event}`);

        // Process webhook deliveries
        if (event._webhookUrl) {
          const response = await fetch(event._webhookUrl, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'X-Event-Type': event.event,
              'X-Event-Id': event.eventId,
            },
            body: JSON.stringify(event),
          });

          if (env.EVENTS_KV) {
            await env.EVENTS_KV.put(
              `delivery:${event.eventId}:${Date.now()}`,
              JSON.stringify({
                webhookUrl: event._webhookUrl,
                status: response.status,
                deliveredAt: new Date().toISOString(),
              }),
              { expirationTtl: 604800 } // 7 days
            );
          }
        }

        message.ack();
      } catch (error) {
        console.error(`[NOTIFICATION] Queue error: ${error.message}`);
        message.retry();
      }
    }
  },
};

async function handleEmitEvent(request, env, ctx) {
  const body = await request.json();
  const { event, ...data } = body;

  if (!event) {
    return jsonResponse({ error: 'Event type is required' }, 400);
  }

  const eventId = crypto.randomUUID();
  const eventRecord = {
    eventId,
    event,
    data,
    emittedAt: new Date().toISOString(),
    source: request.headers.get('X-Service') || 'unknown',
  };

  // Store event in KV
  if (env.EVENTS_KV) {
    await env.EVENTS_KV.put(
      `event:${eventId}`,
      JSON.stringify(eventRecord),
      { expirationTtl: 604800 } // 7 days retention
    );

    // Also store in timeline index
    await env.EVENTS_KV.put(
      `timeline:${Date.now()}:${eventId}`,
      event,
      { expirationTtl: 604800 }
    );
  }

  // Find subscribers and dispatch
  const subscribers = await getSubscribers(event, env);

  if (subscribers.length > 0) {
    // Send to queue for async processing if available
    if (env.EVENTS_QUEUE) {
      for (const subscriber of subscribers) {
        ctx?.waitUntil(
          env.EVENTS_QUEUE.send({
            ...eventRecord,
            _webhookUrl: subscriber.webhookUrl,
            _subscriberId: subscriber.id,
          })
        );
      }
    } else {
      // Fallback: direct webhook delivery (fire-and-forget)
      for (const subscriber of subscribers) {
        ctx?.waitUntil(
          fetch(subscriber.webhookUrl, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'X-Event-Type': event,
              'X-Event-Id': eventId,
            },
            body: JSON.stringify(eventRecord),
          }).catch(err => console.error(`Webhook delivery failed: ${err.message}`))
        );
      }
    }
  }

  // Handle event-specific side effects
  ctx?.waitUntil(processEventSideEffects(event, data, env));

  return jsonResponse({
    success: true,
    eventId,
    event,
    subscribersNotified: subscribers.length,
  });
}

async function processEventSideEffects(event, data, env) {
  // Implement event-specific logic
  switch (event) {
    case 'user.login':
      console.log(`User ${data.email} logged in`);
      if (env.EVENTS_KV) {
        const key = `stats:logins:${new Date().toISOString().split('T')[0]}`;
        const current = parseInt(await env.EVENTS_KV.get(key) || '0', 10);
        await env.EVENTS_KV.put(key, String(current + 1), { expirationTtl: 2592000 }); // 30 days
      }
      break;

    case 'user.profile.updated':
      console.log(`User ${data.userId} updated profile fields: ${data.fields?.join(', ')}`);
      break;

    case 'user.deleted':
      console.log(`User ${data.userId} was deleted`);
      break;

    default:
      console.log(`Unhandled event: ${event}`);
  }
}

async function getSubscribers(eventType, env) {
  if (!env.EVENTS_KV) return [];

  const subscribers = [];
  const list = await env.EVENTS_KV.list({ prefix: 'subscriber:' });

  for (const key of list.keys) {
    const subscriber = await env.EVENTS_KV.get(key.name, { type: 'json' });
    if (subscriber && subscriber.events.includes(eventType) || subscriber?.events.includes('*')) {
      subscribers.push(subscriber);
    }
  }

  return subscribers;
}

async function handleListEvents(request, env) {
  if (!env.EVENTS_KV) {
    return jsonResponse({ events: [] });
  }

  const url = new URL(request.url);
  const limit = parseInt(url.searchParams.get('limit') || '50', 10);
  const eventType = url.searchParams.get('type');

  const timeline = await env.EVENTS_KV.list({ prefix: 'timeline:', limit: limit * 2 });
  const events = [];

  for (const key of timeline.keys.slice(0, limit)) {
    const type = await env.EVENTS_KV.get(key.name);
    if (eventType && type !== eventType) continue;

    const eventId = key.name.split(':')[2];
    const eventRecord = await env.EVENTS_KV.get(`event:${eventId}`, { type: 'json' });
    if (eventRecord) events.push(eventRecord);
  }

  return jsonResponse({ events, total: events.length });
}

async function handleSubscribe(request, env) {
  if (!env.EVENTS_KV) {
    return jsonResponse({ error: 'Event storage not configured' }, 503);
  }

  const body = await request.json();
  const { webhookUrl, events } = body;

  if (!webhookUrl || !events || !Array.isArray(events)) {
    return jsonResponse({ error: 'webhookUrl and events array required' }, 400);
  }

  const subscriberId = crypto.randomUUID();
  const subscriber = {
    id: subscriberId,
    webhookUrl,
    events,
    createdAt: new Date().toISOString(),
  };

  await env.EVENTS_KV.put(`subscriber:${subscriberId}`, JSON.stringify(subscriber));

  return jsonResponse({ success: true, subscriberId, events });
}

async function handleUnsubscribe(request, env) {
  if (!env.EVENTS_KV) {
    return jsonResponse({ error: 'Event storage not configured' }, 503);
  }

  const body = await request.json();
  const { subscriberId } = body;

  if (!subscriberId) {
    return jsonResponse({ error: 'subscriberId required' }, 400);
  }

  await env.EVENTS_KV.delete(`subscriber:${subscriberId}`);
  return jsonResponse({ success: true, unsubscribed: subscriberId });
}

async function handleWebhookDispatch(request, env, ctx) {
  const body = await request.json();
  const { url, payload, retries } = body;

  if (!url || !payload) {
    return jsonResponse({ error: 'url and payload required' }, 400);
  }

  const maxRetries = retries || 3;
  let lastError = null;
  let success = false;

  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const response = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        success = true;
        break;
      }

      lastError = `HTTP ${response.status}`;
    } catch (error) {
      lastError = error.message;
    }

    // Exponential backoff
    if (attempt < maxRetries - 1) {
      await new Promise(resolve => setTimeout(resolve, Math.pow(2, attempt) * 100));
    }
  }

  return jsonResponse({
    success,
    url,
    attempts: success ? undefined : maxRetries,
    error: success ? undefined : lastError,
  });
}

async function handleStats(env) {
  const stats = {
    service: 'notification',
    timestamp: Date.now(),
  };

  if (env.EVENTS_KV) {
    const events = await env.EVENTS_KV.list({ prefix: 'event:' });
    const subscribers = await env.EVENTS_KV.list({ prefix: 'subscriber:' });
    const today = new Date().toISOString().split('T')[0];
    const todayLogins = await env.EVENTS_KV.get(`stats:logins:${today}`);

    stats.totalEvents = events.keys.length;
    stats.totalSubscribers = subscribers.keys.length;
    stats.todayLogins = parseInt(todayLogins || '0', 10);
  }

  return jsonResponse(stats);
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', 'X-Service': 'notification-worker' },
  });
}


// ==========================================
// worker-notification/wrangler.toml
// ==========================================
/*
name = "notification-worker"
main = "src/index.js"
compatibility_date = "2024-01-01"

# No public routes - internal only

[[kv_namespaces]]
binding = "EVENTS_KV"
id = "your-events-kv-id"

# Optional: Queue for async event processing
[[queues.producers]]
binding = "EVENTS_QUEUE"
queue = "events-queue"

[[queues.consumers]]
queue = "events-queue"
max_batch_size = 10
max_retries = 3
*/


// ==========================================
// shared/service-registry.js
// Shared utility for service discovery and communication patterns
// ==========================================

export class ServiceRegistry {
  constructor(env) {
    this.env = env;
    this.services = {
      auth: env.AUTH_SERVICE,
      user: env.USER_SERVICE,
      data: env.DATA_SERVICE,
      notification: env.NOTIFICATION_SERVICE,
    };
  }

  getService(name) {
    const service = this.services[name];
    if (!service) {
      throw new Error(`Service "${name}" not found or not bound`);
    }
    return service;
  }

  async call(serviceName, path, options = {}) {
    const service = this.getService(serviceName);
    const { method = 'GET', body, headers = {} } = options;

    const requestHeaders = new Headers(headers);
    requestHeaders.set('Content-Type', 'application/json');

    const requestInit = {
      method,
      headers: requestHeaders,
    };

    if (body && method !== 'GET' && method !== 'HEAD') {
      requestInit.body = typeof body === 'string' ? body : JSON.stringify(body);
    }

    const response = await service.fetch(
      new Request(`http://internal-service${path}`, requestInit)
    );

    return {
      ok: response.ok,
      status: response.status,
      data: await response.json(),
      headers: Object.fromEntries(response.headers),
    };
  }

  async callWithRetry(serviceName, path, options = {}, retries = 3) {
    let lastError;

    for (let attempt = 0; attempt < retries; attempt++) {
      try {
        const result = await this.call(serviceName, path, options);
        if (result.ok) return result;
        lastError = new Error(`Service returned ${result.status}`);
      } catch (error) {
        lastError = error;
      }

      if (attempt < retries - 1) {
        await new Promise(resolve => setTimeout(resolve, Math.pow(2, attempt) * 50));
      }
    }

    throw lastError;
  }

  async fanOut(calls) {
    const results = await Promise.allSettled(
      calls.map(({ service, path, options }) =>
        this.call(service, path, options)
      )
    );

    return results.map((result, index) => ({
      service: calls[index].service,
      path: calls[index].path,
      status: result.status,
      data: result.status === 'fulfilled' ? result.value.data : null,
      error: result.status === 'rejected' ? result.reason.message : null,
    }));
  }

  async pipeline(steps) {
    let context = {};

    for (const step of steps) {
      const { service, path, options = {}, transform } = step;

      // Allow steps to use context from previous steps
      const resolvedOptions = typeof options === 'function' ? options(context) : options;

      const result = await this.call(service, path, resolvedOptions);

      if (!result.ok) {
        throw new Error(`Pipeline step failed at ${service}${path}: ${result.status}`);
      }

      const stepResult = transform ? transform(result.data) : result.data;
      context = { ...context, [step.name || service]: stepResult };
    }

    return context;
  }

  async healthCheckAll() {
    const results = {};

    for (const [name, binding] of Object.entries(this.services)) {
      if (!binding) {
        results[name] = { status: 'not_configured' };
        continue;
      }

      try {
        const start = Date.now();
        const result = await this.call(name, '/health');
        results[name] = {
          status: result.ok ? 'healthy' : 'degraded',
          latency: `${Date.now() - start}ms`,
          details: result.data,
        };
      } catch (error) {
        results[name] = { status: 'unhealthy', error: error.message };
      }
    }

    return results;
  }
}


// ==========================================
// shared/middleware.js
// Shared middleware utilities for internal workers
// ==========================================

export class RequestMiddleware {
  constructor() {
    this.middlewares = [];
  }

  use(fn) {
    this.middlewares.push(fn);
    return this;
  }

  async execute(request, env, ctx) {
    let index = 0;
    const context = {
      request,
      env,
      ctx,
      state: {},
    };

    const next = async () => {
      if (index < this.middlewares.length) {
        const middleware = this.middlewares[index++];
        return await middleware(context, next);
      }
    };

    return await next();
  }
}

export function rateLimiter(options = {}) {
  const { maxRequests = 100, windowMs = 60000, keyFn } = options;

  return async (context, next) => {
    const { request, env } = context;

    if (!env.RATE_LIMIT_KV) {
      return await next();
    }

    const key = keyFn
      ? keyFn(request)
      : request.headers.get('X-Client-IP') || 'unknown';

    const rateLimitKey = `ratelimit:${key}`;
    const current = parseInt(await env.RATE_LIMIT_KV.get(rateLimitKey) || '0', 10);

    if (current >= maxRequests) {
      return new Response(JSON.stringify({
        error: 'Rate limit exceeded',
        retryAfter: Math.ceil(windowMs / 1000),
      }), {
        status: 429,
        headers: {
          'Content-Type': 'application/json',
          'Retry-After': String(Math.ceil(windowMs / 1000)),
        },
      });
    }

    await env.RATE_LIMIT_KV.put(rateLimitKey, String(current + 1), {
      expirationTtl: Math.ceil(windowMs / 1000),
    });

    return await next();
  };
}

export function requestLogger(serviceName) {
  return async (context, next) => {
    const { request } = context;
    const start = Date.now();
    const requestId = request.headers.get('X-Request-Id') || crypto.randomUUID();

    console.log(`[${serviceName}] >> ${request.method} ${new URL(request.url).pathname} | id=${requestId}`);

    const response = await next();
    const duration = Date.now() - start;

    console.log(`[${serviceName}] << ${response?.status || 'no-response'} | ${duration}ms | id=${requestId}`);

    return response;
  };
}

export function errorHandler(serviceName) {
  return async (context, next) => {
    try {
      return await next();
    } catch (error) {
      console.error(`[${serviceName}] Unhandled error: ${error.message}\n${error.stack}`);
      return new Response(JSON.stringify({
        error: 'Internal Service Error',
        service: serviceName,
        message: error.message,
        requestId: context.request.headers.get('X-Request-Id'),
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' },
      });
    }
  };
}


